import React from 'react';
import { FaCheck } from 'react-icons/fa';
import './MembershipCard.css';

const MembershipCard = ({ membership, onSubscribe }) => {
  const { name, price, duration, features, isPopular } = membership;

  return (
    <div className={`membership-card card ${isPopular ? 'popular' : ''}`}>
      {isPopular && <div className="popular-badge">Most Popular</div>}
      <div className="membership-header">
        <h3>{name}</h3>
        <div className="price">
          <span className="currency">$</span>
          <span className="amount">{price}</span>
          <span className="period">/{duration} days</span>
        </div>
      </div>
      <div className="membership-features">
        <ul>
          {features?.map((feature, index) => (
            <li key={index}>
              <FaCheck className="check-icon" />
              <span>{feature}</span>
            </li>
          ))}
        </ul>
      </div>
      <button 
        className={`btn ${isPopular ? 'btn-primary' : 'btn-secondary'} btn-block`}
        onClick={() => onSubscribe && onSubscribe(membership._id)}
      >
        Choose Plan
      </button>
    </div>
  );
};

export default MembershipCard;
